import { useState, useEffect } from 'react';
import axios from 'axios';
import { toast } from 'react-toastify';

const ScoreBar = ({ score }) => {
  const color = score >= 70 ? '#10b981' : score >= 40 ? '#f59e0b' : '#ef4444';
  return (
    <div className="flex items-center gap-2">
      <div style={{ background: '#0a0d1a', width: 80, height: 5, borderRadius: 3 }}>
        <div style={{ 
          background: color, 
          width: `${score}%`, 
          height: '100%', 
          borderRadius: 3, 
          boxShadow: `0 0 12px ${color}60`,
          transition: 'all 0.6s ease-out'
        }} />
      </div>
      <span style={{ color }} className="text-xs font-bold">{score}</span>
    </div>
  );
};

export default function AdminDashboard() {
  const [projects, setProjects] = useState([]);
  const [stats, setStats] = useState(null);
  const [filter, setFilter] = useState('pending');
  const [loading, setLoading] = useState(true);
  const [actionNote, setActionNote] = useState('');
  const [actionTarget, setActionTarget] = useState(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState(null);
  const [deletingId, setDeletingId] = useState(null);

  useEffect(() => {
    fetchStats();
    fetchProjects();
  }, [filter]);

  const fetchStats = () => {
    axios.get('/api/admin/stats').then(r => setStats(r.data)).catch(console.error);
  };

  const fetchProjects = () => {
    setLoading(true);
    axios.get(`/api/admin/projects?status=${filter}`)
      .then(r => setProjects(r.data))
      .catch(console.error)
      .finally(() => setLoading(false));
  };

  const handleDecision = async (id, decision) => {
    try {
      await axios.patch(`/api/admin/projects/${id}/${decision}`, { adminNote: actionNote });
      toast.success(`Project ${decision}d successfully`);
      setActionTarget(null);
      setActionNote('');
      fetchProjects();
      fetchStats();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Action failed');
    }
  };

  const handleDelete = async (id) => {
    setDeletingId(id);
    try {
      await axios.delete(`/api/admin/projects/${id}`);
      setProjects(prev => prev.filter(p => p._id !== id));
      setConfirmDeleteId(null);
      toast.success('Project deleted successfully.');
      fetchStats();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to delete project.');
    } finally {
      setDeletingId(null);
    }
  };

  const statsList = stats ? [
    { label: 'Total Projects', value: stats.totalProjects, color: '#00d4aa', icon: '📊' },
    { label: 'Pending Review', value: stats.pendingProjects, color: '#f59e0b', icon: '⏳' },
    { label: 'Approved', value: stats.approvedProjects, color: '#10b981', icon: '✓' },
    { label: 'Rejected', value: stats.rejectedProjects, color: '#ef4444', icon: '✗' },
    { label: 'Total Users', value: stats.totalUsers, color: '#8b5cf6', icon: '👥' },
    { label: 'Total Funded', value: `$${(stats.totalFunding || 0).toLocaleString()}`, color: '#06b6d4', icon: '💰' },
  ] : [];

  return (
    <div style={{
      minHeight: '100vh',
      backgroundImage: `url('https://images.unsplash.com/photo-1620712014215-c4ee02842b2b?w=1600&q=80&blend=https://images.unsplash.com/photo-1639152201720-5e536d254160?w=1600&q=80&blend-mode=multiply')`,
      backgroundSize: 'cover',
      backgroundPosition: 'center',
      backgroundAttachment: 'fixed',
      backgroundRepeat: 'no-repeat',
      position: 'relative',
      overflow: 'hidden'
    }}>

      {/* Premium Dark Overlay with Gradient */}
      <div style={{
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        background: `
          linear-gradient(135deg, 
            rgba(10, 13, 26, 0.94) 0%, 
            rgba(10, 13, 26, 0.90) 25%,
            rgba(10, 18, 30, 0.92) 50%,
            rgba(10, 13, 26, 0.91) 75%,
            rgba(10, 13, 26, 0.94) 100%
          ),
          radial-gradient(circle at 20% 50%, rgba(0, 212, 170, 0.06) 0%, transparent 50%),
          radial-gradient(circle at 80% 80%, rgba(139, 92, 246, 0.05) 0%, transparent 50%)
        `,
        pointerEvents: 'none',
        zIndex: 1,
        backdropFilter: 'blur(0.5px)'
      }} />

      {/* Animated Glow Elements */}
      <div style={{
        position: 'fixed',
        top: '-20%',
        left: '-10%',
        width: '500px',
        height: '500px',
        borderRadius: '50%',
        background: 'radial-gradient(circle, rgba(0, 212, 170, 0.12) 0%, transparent 70%)',
        pointerEvents: 'none',
        zIndex: 1,
        filter: 'blur(60px)',
        animation: 'float 25s ease-in-out infinite',
      }} />
      <div style={{
        position: 'fixed',
        bottom: '-15%',
        right: '-10%',
        width: '600px',
        height: '600px',
        borderRadius: '50%',
        background: 'radial-gradient(circle, rgba(139, 92, 246, 0.10) 0%, transparent 70%)',
        pointerEvents: 'none',
        zIndex: 1,
        filter: 'blur(70px)',
        animation: 'float 30s ease-in-out infinite reverse',
      }} />

      {/* Content Grid Pattern Overlay */}
      <div style={{
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        backgroundImage: `linear-gradient(rgba(0, 212, 170, 0.02) 1px, transparent 1px), linear-gradient(90deg, rgba(0, 212, 170, 0.02) 1px, transparent 1px)`,
        backgroundSize: '50px 50px',
        pointerEvents: 'none',
        zIndex: 1,
        opacity: 0.3,
      }} />

      <style>{`
        @keyframes slideUp {
          from {
            opacity: 0;
            transform: translateY(30px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }

        @keyframes slideInRight {
          from {
            opacity: 0;
            transform: translateX(30px);
          }
          to {
            opacity: 1;
            transform: translateX(0);
          }
        }

        @keyframes fadeIn {
          from {
            opacity: 0;
          }
          to {
            opacity: 1;
          }
        }

        @keyframes float {
          0%, 100% {
            transform: translateY(0px);
          }
          50% {
            transform: translateY(40px);
          }
        }

        @keyframes pulse {
          0%, 100% {
            opacity: 1;
          }
          50% {
            opacity: 0.8;
          }
        }

        @keyframes shimmer {
          0% {
            background-position: -1000px 0;
          }
          100% {
            background-position: 1000px 0;
          }
        }

        @keyframes glow {
          0%, 100% {
            box-shadow: 0 0 20px rgba(0, 212, 170, 0.1);
          }
          50% {
            box-shadow: 0 0 30px rgba(0, 212, 170, 0.2);
          }
        }
      `}</style>

      <div className="px-6 py-12 relative z-10">
        <div className="max-w-7xl mx-auto">

          {/* Premium Header */}
          <div className="mb-14" style={{ animation: 'slideUp 0.6s ease-out' }}>
            <div className="flex items-center gap-2 mb-3">
              <span style={{ color: '#00d4aa', fontSize: '24px', filter: 'drop-shadow(0 0 12px rgba(0, 212, 170, 0.6))' }}>⚙</span>
              <span className="text-gray-500 text-xs uppercase tracking-widest font-semibold">Admin Control Center</span>
            </div>
            <div className="flex items-end justify-between mb-4">
              <div>
                <h1 style={{ 
                  fontFamily: 'Syne, sans-serif',
                  background: 'linear-gradient(135deg, #ffffff 0%, #00d4aa 50%, #06b6d4 100%)',
                  backgroundClip: 'text',
                  WebkitBackgroundClip: 'text',
                  WebkitTextFillColor: 'transparent',
                  fontSize: '3.5rem',
                  fontWeight: 900,
                  letterSpacing: '-0.02em',
                  lineHeight: '1',
                }} className="">BackerSphere X</h1>
                <p className="text-gray-400 text-sm mt-3">Enterprise Project Management & AI Evaluation System</p>
              </div>
              <div style={{
                background: 'linear-gradient(135deg, rgba(0, 212, 170, 0.15) 0%, rgba(6, 182, 212, 0.12) 100%)',
                border: '1.5px solid rgba(0, 212, 170, 0.3)',
                borderRadius: '14px',
                padding: '16px 24px',
                backdropFilter: 'blur(15px)',
                animation: 'glow 3s ease-in-out infinite',
              }} className="text-right">
                <div style={{ color: '#00d4aa', fontSize: '11px', fontWeight: 700, letterSpacing: '0.05em' }}>SYSTEM STATUS</div>
                <div className="text-emerald-300 text-sm font-bold mt-2 flex items-center gap-2">
                  <span style={{
                    width: '8px',
                    height: '8px',
                    borderRadius: '50%',
                    background: '#10b981',
                    boxShadow: '0 0 10px #10b981',
                    animation: 'pulse 1.5s ease-in-out infinite'
                  }} />
                  Live & Active
                </div>
              </div>
            </div>
            <div style={{
              height: '3px',
              background: 'linear-gradient(90deg, #00d4aa 0%, #06b6d4 50%, transparent 100%)',
              borderRadius: '2px',
            }} />
          </div>

          {/* Stats Grid - Premium */}
          {stats && (
            <div className="grid grid-cols-6 gap-4 mb-12">
              {statsList.map((s, idx) => (
                <div 
                  key={s.label}
                  style={{
                    background: `linear-gradient(135deg, rgba(17, 24, 39, 0.92) 0%, rgba(15, 23, 42, 0.75) 100%)`,
                    border: `1.5px solid rgba(0, 212, 170, 0.15)`,
                    backdropFilter: 'blur(25px)',
                    transition: 'all 0.4s cubic-bezier(0.4, 0, 0.2, 1)',
                    animation: `slideUp 0.6s ease-out ${idx * 0.08}s both`,
                  }}
                  className="p-6 rounded-2xl text-center hover:shadow-2xl group cursor-pointer"
                  onMouseEnter={(e) => {
                    e.currentTarget.style.borderColor = 'rgba(0, 212, 170, 0.45)';
                    e.currentTarget.style.boxShadow = `0 30px 60px rgba(0, 212, 170, 0.20), inset 0 0 60px rgba(0, 212, 170, 0.10)`;
                    e.currentTarget.style.transform = 'translateY(-6px)';
                    e.currentTarget.style.background = 'linear-gradient(135deg, rgba(17, 24, 39, 0.98) 0%, rgba(15, 23, 42, 0.85) 100%)';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.borderColor = 'rgba(0, 212, 170, 0.15)';
                    e.currentTarget.style.boxShadow = 'none';
                    e.currentTarget.style.transform = 'translateY(0)';
                    e.currentTarget.style.background = 'linear-gradient(135deg, rgba(17, 24, 39, 0.92) 0%, rgba(15, 23, 42, 0.75) 100%)';
                  }}
                >
                  <div style={{ fontSize: '36px', marginBottom: '10px' }}>{s.icon}</div>
                  <div style={{ 
                    color: s.color, 
                    fontFamily: 'Syne, sans-serif', 
                    textShadow: `0 0 25px ${s.color}60`,
                    fontSize: '2.2rem',
                  }} className="font-black">{s.value}</div>
                  <div className="text-gray-500 text-xs mt-3 uppercase tracking-wider font-bold">{s.label}</div>
                  <div style={{ height: '3px', background: `linear-gradient(90deg, ${s.color}40, transparent)`, borderRadius: '2px', marginTop: '10px' }} />
                </div>
              ))}
            </div>
          )}

          {/* Filter Tabs - Premium */}
          <div className="flex gap-3 mb-10 flex-wrap" style={{ animation: 'slideInRight 0.6s ease-out 0.1s both' }}>
            {['pending', 'approved', 'rejected', 'all'].map((f, idx) => (
              <button
                key={f}
                onClick={() => setFilter(f)}
                style={{
                  background: filter === f 
                    ? `linear-gradient(135deg, rgba(0, 212, 170, 0.95) 0%, rgba(6, 182, 212, 0.85) 100%)` 
                    : 'rgba(17, 24, 39, 0.7)',
                  color: filter === f ? '#000a0a' : '#9ca3af',
                  border: filter === f ? '1.5px solid rgba(0, 212, 170, 0.4)' : '1.5px solid rgba(31, 41, 55, 0.8)',
                  boxShadow: filter === f ? '0 15px 40px rgba(0, 212, 170, 0.30)' : 'none',
                  backdropFilter: 'blur(20px)',
                  transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
                }}
                className="px-7 py-3 rounded-xl text-sm font-bold capitalize"
              >
                {f}
              </button>
            ))}
          </div>

          {/* Projects List - Premium */}
          {loading ? (
            <div className="text-center text-gray-500 py-24">
              <div style={{ fontSize: '48px', marginBottom: '16px', animation: 'pulse 1.5s ease-in-out infinite' }}>⏳</div>
              <div className="text-base font-medium">Loading projects...</div>
            </div>
          ) : projects.length === 0 ? (
            <div className="text-center text-gray-500 py-24">
              <div style={{ fontSize: '56px', marginBottom: '16px' }}>📭</div>
              <div className="text-base font-medium">No {filter} projects found</div>
            </div>
          ) : (
            <div className="space-y-5">
              {projects.map((p, idx) => (
                <div
                  key={p._id}
                  style={{
                    background: `linear-gradient(135deg, rgba(17, 24, 39, 0.96) 0%, rgba(15, 23, 42, 0.82) 100%)`,
                    border: '1.5px solid rgba(31, 41, 55, 0.7)',
                    backdropFilter: 'blur(20px)',
                    transition: 'all 0.4s cubic-bezier(0.4, 0, 0.2, 1)',
                    animation: `slideUp 0.6s ease-out ${idx * 0.05}s both`,
                  }}
                  className="rounded-2xl p-8 group"
                  onMouseEnter={(e) => {
                    e.currentTarget.style.boxShadow = '0 50px 100px rgba(0, 212, 170, 0.15), inset 0 0 80px rgba(0, 212, 170, 0.08)';
                    e.currentTarget.style.borderColor = 'rgba(0, 212, 170, 0.35)';
                    e.currentTarget.style.transform = 'translateY(-4px)';
                    e.currentTarget.style.background = 'linear-gradient(135deg, rgba(17, 24, 39, 0.98) 0%, rgba(15, 23, 42, 0.90) 100%)';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.boxShadow = 'none';
                    e.currentTarget.style.borderColor = 'rgba(31, 41, 55, 0.7)';
                    e.currentTarget.style.transform = 'translateY(0)';
                    e.currentTarget.style.background = 'linear-gradient(135deg, rgba(17, 24, 39, 0.96) 0%, rgba(15, 23, 42, 0.82) 100%)';
                  }}
                >

                  <div className="flex items-start justify-between mb-6">
                    <div className="flex-1">
                      <h3 className="font-black text-xl mb-2.5 text-white">{p.title}</h3>
                      <div className="flex gap-4 text-xs text-gray-400 flex-wrap">
                        <span className="flex items-center gap-1.5">👤 {p.innovator?.name}</span>
                        <span>•</span>
                        <span className="flex items-center gap-1.5">🏷️ {p.category}</span>
                        <span>•</span>
                        <span className="flex items-center gap-1.5">🎯 ${p.fundingGoal?.toLocaleString()}</span>
                        <span>•</span>
                        <span className="flex items-center gap-1.5">👥 Team: {p.teamSize}</span>
                      </div>
                    </div>

                    <div className="flex items-center gap-3 ml-6">
                      <span style={{
                        color: p.status === 'approved' ? '#10b981' : p.status === 'rejected' ? '#ef4444' : '#f59e0b',
                        background: p.status === 'approved' ? 'rgba(16, 185, 129, 0.25)' : p.status === 'rejected' ? 'rgba(239, 68, 68, 0.25)' : 'rgba(245, 158, 11, 0.25)',
                        border: `1.5px solid ${p.status === 'approved' ? 'rgba(16, 185, 129, 0.55)' : p.status === 'rejected' ? 'rgba(239, 68, 68, 0.55)' : 'rgba(245, 158, 11, 0.55)'}`,
                        boxShadow: `0 0 25px ${p.status === 'approved' ? '#10b98145' : p.status === 'rejected' ? '#ef444445' : '#f59e0b45'}`,
                        backdropFilter: 'blur(12px)',
                      }} className="px-4 py-2 rounded-full text-xs font-bold capitalize">
                        {p.status}
                      </span>

                      {/* Delete Button */}
                      {confirmDeleteId === p._id ? (
                        <div className="flex items-center gap-2">
                          <span className="text-xs text-gray-400">Confirm?</span>
                          <button
                            onClick={() => handleDelete(p._id)}
                            disabled={deletingId === p._id}
                            style={{
                              background: `linear-gradient(135deg, #ef4444 0%, #dc2626 100%)`,
                              color: 'white',
                              boxShadow: '0 12px 35px rgba(239, 68, 68, 0.45)',
                            }}
                            className="px-4 py-2 rounded-lg text-xs font-bold disabled:opacity-60 transition-all"
                          >
                            {deletingId === p._id ? '⏳' : '✓ Yes'}
                          </button>
                          <button
                            onClick={() => setConfirmDeleteId(null)}
                            style={{ background: 'rgba(31, 41, 55, 0.9)', color: '#9ca3af', border: '1.5px solid rgba(75, 85, 99, 0.6)' }}
                            className="px-4 py-2 rounded-lg text-xs font-bold transition-all"
                          >
                            Cancel
                          </button>
                        </div>
                      ) : (
                        <button
                          onClick={() => setConfirmDeleteId(p._id)}
                          style={{
                            border: '1.5px solid rgba(239, 68, 68, 0.4)',
                            color: '#ef4444',
                            background: 'rgba(239, 68, 68, 0.08)',
                          }}
                          className="px-4 py-2 rounded-lg text-xs font-bold hover:border-red-500 hover:bg-red-500/20"
                        >
                          🗑 Delete
                        </button>
                      )}
                    </div>
                  </div>

                  <p className="text-gray-400 text-sm mb-6 leading-relaxed">{p.description}</p>

                  {/* AI Scores - Premium */}
                  {p.aiEvaluation?.feasibilityScore !== null ? (
                    <div style={{
                      background: `linear-gradient(135deg, rgba(10, 13, 26, 0.96) 0%, rgba(10, 15, 30, 0.88) 100%)`,
                      border: '1.5px solid rgba(0, 212, 170, 0.35)',
                      boxShadow: '0 0 50px rgba(0, 212, 170, 0.15), inset 0 0 50px rgba(0, 212, 170, 0.08)',
                      backdropFilter: 'blur(20px)',
                    }} className="rounded-2xl p-6 mb-6">
                      <p style={{ color: '#00d4aa', textShadow: '0 0 20px rgba(0, 212, 170, 0.5)' }} className="text-xs font-black uppercase tracking-widest mb-5">
                        ✦ Gemini AI Evaluation
                      </p>
                      <div className="grid grid-cols-2 gap-5 mb-5">
                        <div>
                          <div className="text-gray-500 text-xs mb-3 uppercase tracking-wide font-bold">Feasibility Score</div>
                          <ScoreBar score={p.aiEvaluation.feasibilityScore} />
                        </div>
                        <div>
                          <div className="text-gray-500 text-xs mb-3 uppercase tracking-wide font-bold">Success Probability</div>
                          <ScoreBar score={p.aiEvaluation.successProbability} />
                        </div>
                      </div>
                      <div style={{ borderTop: '1px solid rgba(0, 212, 170, 0.15)' }} className="pt-4">
                        <p className="text-gray-400 text-xs leading-relaxed">{p.aiEvaluation.explanation}</p>
                      </div>
                    </div>
                  ) : (
                    <div style={{ color: '#f59e0b' }} className="text-sm mb-6 font-medium">⏳ AI evaluation in progress...</div>
                  )}

                  {/* Approve / Reject Actions */}
                  {p.status === 'pending' && (
                    <div>
                      {actionTarget === p._id ? (
                        <div className="flex gap-3 items-center">
                          <input
                            value={actionNote}
                            onChange={e => setActionNote(e.target.value)}
                            style={{
                              background: 'rgba(10, 13, 26, 0.96)',
                              border: '1.5px solid rgba(0, 212, 170, 0.25)',
                              color: 'white',
                              backdropFilter: 'blur(15px)',
                            }}
                            className="flex-1 px-5 py-3 rounded-xl text-sm focus:outline-none focus:border-teal-500 transition-all"
                            placeholder="Admin note (optional)..."
                          />
                          <button
                            onClick={() => handleDecision(p._id, 'approve')}
                            style={{
                              background: `linear-gradient(135deg, #10b981 0%, #059669 100%)`,
                              color: 'white',
                              boxShadow: '0 12px 35px rgba(16, 185, 129, 0.45)',
                            }}
                            className="px-6 py-3 rounded-xl text-sm font-bold transition-all"
                          >
                            ✓ Approve
                          </button>
                          <button
                            onClick={() => handleDecision(p._id, 'reject')}
                            style={{
                              background: `linear-gradient(135deg, #ef4444 0%, #dc2626 100%)`,
                              color: 'white',
                              boxShadow: '0 12px 35px rgba(239, 68, 68, 0.45)',
                            }}
                            className="px-6 py-3 rounded-xl text-sm font-bold transition-all"
                          >
                            ✗ Reject
                          </button>
                          <button
                            onClick={() => { setActionTarget(null); setActionNote(''); }}
                            className="text-gray-400 text-sm font-medium hover:text-gray-300 transition-all"
                          >
                            Cancel
                          </button>
                        </div>
                      ) : (
                        <button
                          onClick={() => setActionTarget(p._id)}
                          style={{
                            border: '1.5px solid rgba(0, 212, 170, 0.35)',
                            color: '#9ca3af',
                            background: 'rgba(0, 212, 170, 0.10)',
                            backdropFilter: 'blur(15px)',
                          }}
                          className="px-6 py-3 rounded-xl text-sm font-bold hover:border-teal-500 hover:text-white hover:bg-teal-500/25"
                        >
                          🔍 Review & Decide
                        </button>
                      )}
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
